// src/components/Sidebar.jsx
import { FaHome, FaComments, FaCalendarAlt } from "react-icons/fa";

export default function Sidebar() {
  return (
    <div className="w-20 bg-white border-r flex flex-col items-center py-4">
      <button className="mb-6 p-2 bg-purple-100 rounded-full">
        <FaHome size={20} />
      </button>
      <button className="mb-6 p-2 hover:bg-purple-100 rounded-full">
        <FaComments size={20} />
      </button>
      <button className="mb-6 p-2 hover:bg-purple-100 rounded-full">
        <FaCalendarAlt size={20} />
      </button>
    </div>
  );
}
